+export interface DurationHistoryEntry {
+  duration?: number
+  recordedAt?: number
+  observations?: DurationObservation[]
+}
+
+export type DurationHistory = Record<string, DurationHistoryEntry | number>
+
+export function getDurationHistoryPath(root: string, historyPath: string): string {
+  return resolve(root, historyPath)
+}
+
+export function getObservations(entry: DurationHistoryEntry | number | undefined, ttl: number, now = Date.now()): DurationObservation[] {
+  const observations = typeof entry === 'number'
+    ? [{ duration: entry, recordedAt: 0 }]
+    : entry?.observations ?? (entry?.duration == null ? [] : [{ duration: entry.duration, recordedAt: entry.recordedAt ?? 0 }])
+  const expiry = now - ttl
+  return observations.filter(observation => observation.recordedAt === 0 || ttl <= 0 || observation.recordedAt >= expiry)
+}
+
+export async function readDurationHistory(root: string, historyPath: string): Promise<DurationHistory | null> {
+  try {
+    const value = JSON.parse(await fs.readFile(getDurationHistoryPath(root, historyPath), 'utf8'))
+    return value && typeof value === 'object' && !Array.isArray(value) ? value : null
+  }
+  catch {
+    return null
+  }
+}
+
+export function getSmoothedDuration(history: DurationHistory, path: string, ttl: number, smoothing: DurationSmoothing): number {
+  return smoothDurations(getObservations(history[path], ttl), smoothing)
+}
+
+export async function writeDurationHistory(
+  root: string,
+  historyPath: string,
+  durations: Record<string, number>,
+  ttl: number,
+  maxRuns: number,
+): Promise<void> {
+  const file = getDurationHistoryPath(root, historyPath)
+  const history = await readDurationHistory(root, historyPath) ?? {}
+  const now = Date.now()
+  for (const [path, duration] of Object.entries(durations)) {
+    const observations = [...getObservations(history[path], ttl, now), { duration: Math.round(duration), recordedAt: now }]
+      .sort((a, b) => b.recordedAt - a.recordedAt)
+      .slice(0, maxRuns)
+    history[path] = maxRuns === 1 ? observations[0] : { observations }
+  }
+  await fs.mkdir(dirname(file), { recursive: true })
+  await fs.writeFile(file, JSON.stringify(history, null, 2), 'utf8')
